public class State {
    interface TrafficLight { void signal(); TrafficLight next(); }
    enum Light implements TrafficLight {
        RED   { public void signal(){System.out.println("Stop");} public TrafficLight next(){return GREEN;} },
        GREEN { public void signal(){System.out.println("Go");} public TrafficLight next(){return YELLOW;} },
        YELLOW{ public void signal(){System.out.println("Caution");} public TrafficLight next(){return RED;} };
    }
    public static void main(String[] args) {
        TrafficLight t = Light.RED;
        for (int i = 0; i < 4; i++) {
            t.signal();
            t = t.next();
        }
    }
